def _semantic_case(case: EvalCase) -> EvalCase:
    return EvalCase(**{**case.__dict__, "scorer": None, "judge": True})


CASES = tuple(_semantic_case(case) if case.id in UNRESTORED_SEMANTIC_CASE_IDS else case for case in CASES)
